INSERT INTO questions (difficulty, question_text, options, correct_answer_old, correct_index, explanation) VALUES
('elementary', 'I ___ a student.', '["A. am", "B. is", "C. are", "D. be"]'::jsonb, 'A', 0, '主詞 I 搭配 be 動詞 am。'),
('elementary', 'She ___ my sister.', '["A. am", "B. is", "C. are", "D. be"]'::jsonb, 'B', 1, '第三人稱單數 she 用 is。'),
('elementary', 'They ___ playing soccer.', '["A. is", "B. am", "C. are", "D. be"]'::jsonb, 'C', 2, '複數主詞 they 用 are。'),
('elementary', 'What ___ your name?', '["A. are", "B. is", "C. am", "D. be"]'::jsonb, 'B', 1, '單數主詞 your name 視為單一概念，用 is。'),
('elementary', 'There ___ five apples.', '["A. is", "B. are", "C. am", "D. be"]'::jsonb, 'B', 1, '後接複數名詞用 there are。'),
('elementary', 'He ___ not like coffee.', '["A. do", "B. does", "C. is", "D. are"]'::jsonb, 'B', 1, '第三人稱否定喜好用 does not。'),
('elementary', '___ you like tea?', '["A. Do", "B. Does", "C. Is", "D. Are"]'::jsonb, 'A', 0, 'you 搭配助動詞 Do 構成疑問。'),
('elementary', 'I have ___ umbrella.', '["A. a", "B. an", "C. the", "D. no article"]'::jsonb, 'B', 1, 'umbrella 母音開頭，冠詞用 an。'),
('elementary', 'This is ___ book.', '["A. a", "B. an", "C. the", "D. no article"]'::jsonb, 'A', 0, 'book 子音開頭，不定冠詞用 a。'),
('elementary', 'Those ___ my shoes.', '["A. is", "B. are", "C. am", "D. be"]'::jsonb, 'B', 1, 'those 為複數指示代名詞，動詞用 are。'),
('elementary', 'She ___ to school every day.', '["A. go", "B. goes", "C. going", "D. went"]'::jsonb, 'B', 1, '每天習慣用現在簡單式，she 加 -es。'),
('elementary', 'We ___ English on Mondays.', '["A. study", "B. studies", "C. studying", "D. studied"]'::jsonb, 'A', 0, 'We 為複數主詞，動詞用原形 study。'),
('elementary', 'It ___ raining now.', '["A. is", "B. are", "C. am", "D. be"]'::jsonb, 'A', 0, '現在進行式：It is + V-ing。'),
('elementary', 'Can you ___ me?', '["A. help", "B. helps", "C. helping", "D. helped"]'::jsonb, 'A', 0, '情態動詞 can 後接動詞原形。'),
('elementary', 'I ___ breakfast at 7 a.m.', '["A. eat", "B. eats", "C. eating", "D. ate"]'::jsonb, 'A', 0, 'I 第一人稱，現在簡單式用 eat。'),
('elementary', 'He ___ his homework yesterday.', '["A. do", "B. does", "C. did", "D. doing"]'::jsonb, 'C', 2, 'yesterday 表過去，助動詞用 did（此處選項為過去式動詞 did 表「做」—若題幹為 finish 類會不同；此題選 did 表完成過去動作）。'),
('elementary', 'They ___ TV last night.', '["A. watch", "B. watches", "C. watching", "D. watched"]'::jsonb, 'D', 3, 'last night 過去時間，動詞用過去式 watched。'),
('elementary', '___ is your birthday?', '["A. When", "B. Where", "C. Who", "D. How"]'::jsonb, 'A', 0, '詢問日期用 When。'),
('elementary', '___ bag is this?', '["A. Who", "B. Whose", "C. Which", "D. What"]'::jsonb, 'B', 1, '詢問物品所屬用 Whose。'),
('elementary', 'I am ___ years old.', '["A. seven", "B. seventh", "C. sevens", "D. sevenths"]'::jsonb, 'A', 0, '年齡用基數詞 seven。'),
('elementary', 'The cat is ___ the table.', '["A. in", "B. on", "C. at", "D. of"]'::jsonb, 'B', 1, '在桌面上用介系詞 on。'),
('elementary', 'The keys are ___ my pocket.', '["A. on", "B. in", "C. at", "D. by"]'::jsonb, 'B', 1, '在口袋內部用 in。'),
('elementary', 'She goes to school ___ bus.', '["A. by", "B. on", "C. in", "D. with"]'::jsonb, 'A', 0, '交通工具用 by bus。'),
('elementary', '___! You won the game.', '["A. Congratulations", "B. Sorry", "C. Excuse me", "D. Goodbye"]'::jsonb, 'A', 0, '祝賀對方獲勝用 Congratulations。'),
('elementary', 'It''s cold. Please ___ the window.', '["A. open", "B. opens", "C. opening", "D. opened"]'::jsonb, 'A', 0, '祈使句請求，動詞用原形 open。'),
('elementary', 'Don''t ___ in the library.', '["A. talk", "B. talks", "C. talking", "D. talked"]'::jsonb, 'A', 0, '否定祈使 Don''t 後接動詞原形。'),
('elementary', 'How ___ apples do you want?', '["A. much", "B. many", "C. old", "D. long"]'::jsonb, 'B', 1, '可數名詞數量用 How many。'),
('elementary', 'How ___ water do you need?', '["A. many", "B. much", "C. often", "D. far"]'::jsonb, 'B', 1, '不可數名詞用量用 How much。'),
('elementary', 'I have ___ brother and two sisters.', '["A. one", "B. an", "C. much", "D. any"]'::jsonb, 'A', 0, '一位哥哥／弟弟用 one 或 a；選項 one 正確。'),
('elementary', 'This pencil is ___.', '["A. you", "B. your", "C. yours", "D. you''re"]'::jsonb, 'C', 2, '名詞後表示「你的（東西）」用名詞性物主代名詞 yours。'),
('elementary', '___ pen is on the floor?', '["A. Who", "B. Whose", "C. Where", "D. When"]'::jsonb, 'B', 1, '問「誰的筆」用 Whose。'),
('elementary', 'We should ___ our teeth before bed.', '["A. brush", "B. brushes", "C. brushing", "D. brushed"]'::jsonb, 'A', 0, '情態動詞 should 後接原形 brush。'),
('elementary', 'It''s 10 p.m. Let''s ___ to bed.', '["A. go", "B. goes", "C. going", "D. went"]'::jsonb, 'A', 0, 'Let''s 後接動詞原形 go。'),
('elementary', 'The sun ___ in the east.', '["A. rise", "B. rises", "C. rising", "D. rose"]'::jsonb, 'B', 1, '自然現象習慣用現在式，the sun 為單數用 rises。'),
('elementary', 'Birds can ___.', '["A. fly", "B. flies", "C. flying", "D. flew"]'::jsonb, 'A', 0, '情態動詞 can 後接原形 fly。'),
('elementary', 'I want ___ apple juice.', '["A. a", "B. an", "C. some", "D. any"]'::jsonb, 'C', 2, '不可數的果汁表示「一些」用 some（肯定句）。'),
('elementary', 'There isn''t ___ milk in the fridge.', '["A. some", "B. any", "C. many", "D. a"]'::jsonb, 'B', 1, '否定句中「任何」用 any。'),
('elementary', 'My father ___ tall.', '["A. am", "B. is", "C. are", "D. be"]'::jsonb, 'B', 1, 'My father 第三人稱單數用 is。'),
('elementary', 'These ___ not my books.', '["A. is", "B. are", "C. am", "D. be"]'::jsonb, 'B', 1, 'these 複數用 are。'),
('elementary', '___ you OK?', '["A. Is", "B. Are", "C. Am", "D. Be"]'::jsonb, 'B', 1, '主詞 you 配 Are。'),
('elementary', 'Welcome ___ our school!', '["A. for", "B. to", "C. at", "D. on"]'::jsonb, 'B', 1, 'Welcome to + 地點為固定用法。'),
('elementary', 'Nice ___ meet you.', '["A. too", "B. to", "C. for", "D. of"]'::jsonb, 'B', 1, '初次見面固定句 Nice to meet you。'),
('elementary', 'See you ___.', '["A. tomorrow", "B. tomorrows", "C. in tomorrow", "D. at tomorrow"]'::jsonb, 'A', 0, '明天見用 tomorrow。'),
('elementary', '___ is this? — It''s a ruler.', '["A. What", "B. Who", "C. Where", "D. How"]'::jsonb, 'A', 0, '詢問物品是什麼用 What。'),
('elementary', '___ is he from? — Taiwan.', '["A. What", "B. Where", "C. When", "D. Why"]'::jsonb, 'B', 1, '詢問來自哪裡用 Where。'),
('elementary', 'I like ___ because it''s sweet.', '["A. candy", "B. salt", "C. spicy", "D. sour"]'::jsonb, 'A', 0, '甜的東西符合 candy。'),
('elementary', 'We wear coats when it''s ___.', '["A. hot", "B. cold", "C. sunny", "D. warm"]'::jsonb, 'B', 1, '穿外套通常是天冷時。'),
('elementary', 'Monday comes ___ Sunday.', '["A. before", "B. after", "C. at", "D. on"]'::jsonb, 'B', 1, '星期一在星期日之後。'),
('elementary', 'There are seven ___ in a week.', '["A. hours", "B. days", "C. months", "D. years"]'::jsonb, 'B', 1, '一週有七天 days。'),
('elementary', 'January is the first ___ of the year.', '["A. week", "B. day", "C. month", "D. season"]'::jsonb, 'C', 2, '一月是一年中的第一個月。'),
('elementary', 'Red and yellow make ___.', '["A. green", "B. orange", "C. purple", "D. black"]'::jsonb, 'B', 1, '紅加黃成橙色（題目常識）。'),
('elementary', 'A dog says ___.', '["A. meow", "B. woof", "C. moo", "D. oink"]'::jsonb, 'B', 1, '狗叫聲常用 woof。'),
('elementary', 'An elephant is ___.', '["A. small", "B. tiny", "C. large", "D. short"]'::jsonb, 'C', 2, '大象體型大，選 large。'),
('elementary', 'We use ___ to cut paper.', '["A. a spoon", "B. a fork", "C. scissors", "D. a plate"]'::jsonb, 'C', 2, '剪刀剪裁紙張。'),
('elementary', 'You read books in the ___.', '["A. kitchen", "B. classroom", "C. library", "D. gym"]'::jsonb, 'C', 2, '在圖書館閱讀。'),
('elementary', 'Doctors work in a ___.', '["A. school", "B. hospital", "C. farm", "D. zoo"]'::jsonb, 'B', 1, '醫師在醫院工作。'),
('elementary', 'An orange is usually ___.', '["A. blue", "B. orange", "C. black", "D. white"]'::jsonb, 'B', 1, '橘子通常橙色。'),
('elementary', 'We sleep in the ___.', '["A. kitchen", "B. garden", "C. bedroom", "D. street"]'::jsonb, 'C', 2, '在臥房睡覺。'),
('elementary', 'The opposite of ''big'' is ___.', '["A. large", "B. huge", "C. small", "D. tall"]'::jsonb, 'C', 2, 'big 的反義是 small。'),
('elementary', '12 minus 5 equals ___.', '["A. five", "B. six", "C. seven", "D. eight"]'::jsonb, 'C', 2, '12-5=7。'),
('elementary', 'Which season is the hottest?', '["A. spring", "B. summer", "C. fall", "D. winter"]'::jsonb, 'B', 1, '通常夏季最熱。'),
('elementary', 'You drink soup with a ___.', '["A. knife", "B. spoon", "C. chopsticks", "D. cup"]'::jsonb, 'B', 1, '湯一般用湯匙。'),
('elementary', 'A triangle has ___ sides.', '["A. two", "B. three", "C. four", "D. five"]'::jsonb, 'B', 1, '三角形有三邊。'),
('elementary', 'We celebrate Christmas in ___.', '["A. July", "B. December", "C. March", "D. June"]'::jsonb, 'B', 1, '聖誕節在十二月。'),
('elementary', 'A week has ___ days.', '["A. five", "B. six", "C. seven", "D. eight"]'::jsonb, 'C', 2, '一週七天。'),
('elementary', 'The first month is ___.', '["A. February", "B. January", "C. March", "D. April"]'::jsonb, 'B', 1, '第一個月是一月。'),
('elementary', 'If you are thirsty, you should ___.', '["A. sleep", "B. drink water", "C. run", "D. sing"]'::jsonb, 'B', 1, '口渴應喝水。'),
('elementary', 'Good night means we say it ___.', '["A. in the morning", "B. before sleep", "C. at lunch", "D. in class"]'::jsonb, 'B', 1, '晚安在睡前說。'),
('elementary', 'We write with a ___.', '["A. plate", "B. pen", "C. spoon", "D. chair"]'::jsonb, 'B', 1, '用筆書寫。'),
('elementary', 'Which animal can swim?', '["A. bird only", "B. fish", "C. only cats", "D. only cows"]'::jsonb, 'B', 1, '魚會游泳。'),
('elementary', 'Please ___ your teacher.', '["A. ignore", "B. respect", "C. shout at", "D. fight"]'::jsonb, 'B', 1, '應尊敬老師。'),
('elementary', '___ comes after Tuesday.', '["A. Monday", "B. Wednesday", "C. Sunday", "D. Friday"]'::jsonb, 'B', 1, '週三在週二之後。'),
('elementary', 'We eat rice with ___.', '["A. only hands in class", "B. chopsticks in many places", "C. never", "D. shoes"]'::jsonb, 'B', 1, '許多地區用筷子吃飯。'),
('elementary', '___ means ''Not bad.'' in many chats.', '["A. Terrible", "B. So-so", "C. Perfect", "D. Excellent"]'::jsonb, 'B', 1, 'So-so 表示普通、還可以。'),
('elementary', 'Turn left means go to the ___.', '["A. right side", "B. left side", "C. back only", "D. sky"]'::jsonb, 'B', 1, '左轉即往左邊。'),
('junior', 'If it rains tomorrow, we ___ the picnic.', '["A. cancel", "B. cancelled", "C. have cancelled", "D. will cancel"]'::jsonb, 'D', 3, '第一條件句：if + 現在簡單，主句用未來 will。'),
('junior', 'She ___ English for five years.', '["A. studies", "B. has studied", "C. studied", "D. is studying"]'::jsonb, 'B', 1, 'for + 一段時間表從過去持續至今，常用現在完成式。'),
('junior', 'By next July, he ___ here for ten years.', '["A. lives", "B. will live", "C. will have lived", "D. lived"]'::jsonb, 'C', 2, 'By + 未來時間點表「到那時將已…」，用未來完成式。'),
('junior', 'I wish I ___ taller.', '["A. am", "B. was", "C. were", "D. be"]'::jsonb, 'C', 2, 'wish 後假設與現在事實相反，be 動詞常用 were。'),
('junior', 'It''s time we ___ home.', '["A. go", "B. went", "C. gone", "D. going"]'::jsonb, 'B', 1, 'It''s time (that) + 過去式表「該是…的時候了」。'),
('junior', 'The book ___ by millions of readers.', '["A. reads", "B. is read", "C. was reading", "D. has read"]'::jsonb, 'B', 1, '書被閱讀，被動語態。'),
('junior', 'He decided ___ abroad.', '["A. study", "B. studying", "C. to study", "D. studied"]'::jsonb, 'C', 2, 'decide 後接不定詞 to study。'),
('junior', 'She is interested ___ music.', '["A. on", "B. at", "C. in", "D. for"]'::jsonb, 'C', 2, 'be interested in 為固定搭配。'),
('junior', 'Neither Tom nor his brothers ___ coming.', '["A. is", "B. are", "C. was", "D. be"]'::jsonb, 'B', 1, 'Neither nor 動詞與最近主詞 brothers 一致。'),
('junior', 'Not only Jane but also her friends ___ there.', '["A. was", "B. were", "C. is", "D. be"]'::jsonb, 'B', 1, 'Not only but also 動詞與較近主詞 friends 一致。'),
('junior', 'The news ___ surprising.', '["A. are", "B. were", "C. is", "D. be"]'::jsonb, 'C', 2, 'news 為不可數，視為單數。'),
('junior', 'Mathematics ___ my favorite subject.', '["A. are", "B. were", "C. is", "D. be"]'::jsonb, 'C', 2, '學科 mathematics 當單數。'),
('junior', 'Few students finished it; ___, most gave up.', '["A. therefore", "B. moreover", "C. however", "D. for example"]'::jsonb, 'C', 2, '語意轉折，用 however。'),
('junior', 'She runs fast; ___, she won the race.', '["A. but", "B. therefore", "C. although", "D. unless"]'::jsonb, 'B', 1, '因果：跑得快因此獲勝，用 therefore。'),
('junior', '___ it was cold, we went swimming.', '["A. Because", "B. Although", "C. If", "D. Unless"]'::jsonb, 'B', 1, '儘管冷還是去游泳，讓步用 Although。'),
('junior', 'You ___ smoke here; it''s forbidden.', '["A. must", "B. mustn''t", "C. should", "D. might"]'::jsonb, 'B', 1, '禁止用 mustn''t。'),
('junior', 'You ___ see a doctor if the pain continues.', '["A. mustn''t", "B. should", "C. might not", "D. couldn''t"]'::jsonb, 'B', 1, '建議應該看醫生用 should。'),
('junior', 'He speaks ___ he were an expert.', '["A. even if", "B. as though", "C. unless", "D. until"]'::jsonb, 'B', 1, '好像、彷彿用 as though / as if。'),
('junior', 'No sooner ___ than the phone rang.', '["A. he sat down", "B. had he sat down", "C. he had sat down", "D. did he sat down"]'::jsonb, 'B', 1, 'No sooner 倒裝且過去完成。'),
('junior', 'Scarcely ___ when the lights went out.', '["A. the show began", "B. had the show begun", "C. did the show began", "D. the show had begun"]'::jsonb, 'B', 1, 'Scarcely...when 結構常用過去完成倒裝。'),
('junior', 'I''d rather you ___ now.', '["A. leave", "B. left", "C. leaving", "D. to leave"]'::jsonb, 'B', 1, 'would rather + 子句表對他人行為願望時常用過去式。'),
('junior', 'If I ___ you, I would apologize.', '["A. am", "B. was", "C. were", "D. had been"]'::jsonb, 'C', 2, '與現在事實相反的第二條件 if I were you。'),
('junior', 'The man ___ wallet was stolen reported it.', '["A. who", "B. whom", "C. whose", "D. which"]'::jsonb, 'C', 2, '所有格關係代名詞 whose。'),
('junior', 'This is the best film ___ I have ever seen.', '["A. which", "B. that", "C. what", "D. who"]'::jsonb, 'B', 1, '先行詞有最高級修飾時關係代名詞常用 that。'),
('junior', 'He has three brothers, all of ___ are doctors.', '["A. them", "B. which", "C. whom", "D. who"]'::jsonb, 'C', 2, '介詞 + whom 指人（brothers）。'),
('junior', 'She suggested that he ___ early.', '["A. leave", "B. leaves", "C. left", "D. leaving"]'::jsonb, 'A', 0, 'suggest that + 原形動詞（英式／正式）或 should leave。'),
('junior', 'It''s essential that he ___ on time.', '["A. be", "B. is", "C. was", "D. will be"]'::jsonb, 'A', 0, 'essential that + (should) + 原形。'),
('junior', 'Hardly ___ when she started to cry.', '["A. the movie began", "B. had the movie begun", "C. did the movie began", "D. the movie had begun"]'::jsonb, 'B', 1, 'Hardly...when 與過去完成倒裝。'),
('junior', 'So difficult ___ that nobody solved it.', '["A. the problem was", "B. was the problem", "C. did the problem be", "D. the problem is"]'::jsonb, 'B', 1, 'So + 形／副 前置倒裝。'),
('junior', 'Not until yesterday ___ the truth.', '["A. I knew", "B. did I know", "C. I had known", "D. had I knew"]'::jsonb, 'B', 1, 'Not until 開頭需倒裝。'),
('junior', 'The cake smells ___.', '["A. nicely", "B. good", "C. well", "D. best"]'::jsonb, 'B', 1, '感官動詞 smell 後接形容詞 good。'),
('junior', 'He felt ___ about failing the exam.', '["A. badly", "B. bad", "C. worst", "D. badder"]'::jsonb, 'B', 1, 'feel 後接形容詞 bad。'),
('junior', 'She looked ___ at him.', '["A. angry", "B. angrily", "C. anger", "D. angrier"]'::jsonb, 'B', 1, '修飾動詞 look 用副詞 angrily。'),
('junior', 'I look forward ___ from you.', '["A. to hear", "B. to hearing", "C. hearing", "D. hear"]'::jsonb, 'B', 1, 'look forward to + 動名詞。'),
('junior', 'She accused him ___ lying.', '["A. for", "B. of", "C. with", "D. about"]'::jsonb, 'B', 1, 'accuse someone of + 動名詞。'),
('junior', 'You''d better ___ now.', '["A. to leave", "B. leave", "C. leaving", "D. left"]'::jsonb, 'B', 1, 'had better 後接動詞原形。'),
('junior', 'It''s no use ___ over spilt milk.', '["A. cry", "B. to cry", "C. crying", "D. cried"]'::jsonb, 'C', 2, 'It''s no use + 動名詞。'),
('junior', 'The problem ___ at the meeting yesterday.', '["A. discusses", "B. was discussed", "C. discussed", "D. is discussing"]'::jsonb, 'B', 1, '問題被討論，過去被動。'),
('junior', 'The teacher made the students ___ quietly.', '["A. to sit", "B. sit", "C. sitting", "D. sat"]'::jsonb, 'B', 1, 'make + 受詞 + 原形動詞。'),
('junior', 'Let me ___ you with your bags.', '["A. to help", "B. help", "C. helping", "D. helped"]'::jsonb, 'B', 1, 'let + 受詞 + 原形動詞。'),
('junior', 'He used ___ in Paris.', '["A. living", "B. to live", "C. live", "D. lived"]'::jsonb, 'B', 1, 'used to + 原形表過去習慣。'),
('junior', 'The boy ___ window was broken must pay.', '["A. who", "B. whom", "C. whose", "D. which"]'::jsonb, 'C', 2, '男孩之窗戶，用 whose。'),
('junior', 'This is the house ___ Shakespeare was born.', '["A. which", "B. where", "C. that", "D. what"]'::jsonb, 'B', 1, '地點先行詞用 where。'),
('junior', 'I don''t know ___ he will come.', '["A. if", "B. that", "C. what", "D. which"]'::jsonb, 'A', 0, 'whether/if 引導名詞子句表「是否」。'),
('junior', 'Tell me ___ you want.', '["A. what", "B. that", "C. which", "D. what that"]'::jsonb, 'A', 0, '疑問詞 what 作 want 的受詞。'),
('junior', '___ breaks the rules will be punished.', '["A. Whoever", "B. Who", "C. Whom", "D. Whose"]'::jsonb, 'A', 0, '無論誰違規，用 whoever。'),
('junior', '___ difficult the task is, we must finish it.', '["A. However", "B. Whatever", "C. Although", "D. Though"]'::jsonb, 'A', 0, 'However + 形／副 表「無論多…」。'),
('junior', 'He is ___ smart that everyone admires him.', '["A. so", "B. such", "C. very", "D. too"]'::jsonb, 'A', 0, 'so...that 結果子句。'),
('junior', 'It was ___ a cold day that we stayed inside.', '["A. so", "B. such", "C. very", "D. much"]'::jsonb, 'B', 1, 'such + a + 形 + 名。'),
('junior', 'By the time we arrived, the film ___.', '["A. starts", "B. had started", "C. has started", "D. was starting"]'::jsonb, 'B', 1, '動作發生在 arrived 之前，過去完成。'),
('junior', 'She ___ the essay before the deadline.', '["A. has finished", "B. had finished", "C. finished", "D. finishes"]'::jsonb, 'B', 1, '在過去某點之前已完成，過去完成。'),
('junior', 'If I ___ harder, I would have passed.', '["A. study", "B. studied", "C. had studied", "D. have studied"]'::jsonb, 'C', 2, '與過去事實相反的第三條件。'),
