('junior', 'I''d prefer ___ at home tonight.', '["A. stay", "B. to stay", "C. staying", "D. stayed"]'::jsonb, 'B', 1, 'would prefer + to + 原形。'),
('junior', 'Rather than ___ , he walked.', '["A. wait", "B. to wait", "C. waiting", "D. waited"]'::jsonb, 'A', 0, 'rather than + 原形。'),
('junior', 'It ___ John who broke the vase.', '["A. is", "B. was", "C. were", "D. are"]'::jsonb, 'B', 1, '分裂句 It was... who，過去事件。'),
